select 
from question


        and type_id = #{typeId}


        and creator_id = #{creatorId}


        and department_id = #{departmentId}


        and title like concat('%', #{title}, '%')


        and difficulty = #{difficulty}


        and status = #{status}


        and tags like concat('%', #{tags}, '%')


order by create_time desc

