type_id = #{typeId}, type_name = #{typeName}, title = #{title}, option_a = #{optionA}, option_b = #{optionB}, option_c = #{optionC}, option_d = #{optionD}, answer = #{answer}, analysis = #{analysis}, tags = #{tags}, image_url = #{imageUrl}, video_url = #{videoUrl}, difficulty = #{difficulty}, status = #{status},
where id = #{id}
